import { describe, it, expect } from 'vitest';
import { testApiHandler } from 'next-test-api-route-handler';
import * as appHandler from '@/app/api/contact/route';

describe('POST /api/contact', () => {
  it('creates contact submission with valid data', async () => {
    await testApiHandler({
      appHandler,
      test: async ({ fetch }) => {
        const response = await fetch({
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            name: 'John Doe',
            email: 'john@example.com',
            message: 'Test message'
          })
        });

        expect(response.status).toBe(201);
        const data = await response.json();
        expect(data.success).toBe(true);
        expect(data.id).toBeDefined();
      }
    });
  });

  it('returns 400 for invalid email', async () => {
    await testApiHandler({
      appHandler,
      test: async ({ fetch }) => {
        const response = await fetch({
          method: 'POST',
          body: JSON.stringify({
            name: 'John',
            email: 'invalid-email',
            message: 'Test'
          })
        });

        expect(response.status).toBe(400);
        const data = await response.json();
        expect(data.errors.email).toBeDefined();
      }
    });
  });
});

import { test, expect } from '@playwright/test';

test.describe('Contact Form Submission', () => {
  test('user can submit contact form successfully', async ({ page }) => {
    // Navigate to contact page
    await page.goto('/contact');

    // Fill out form
    await page.fill('input[name="name"]', 'Jane Doe');
    await page.fill('input[name="email"]', 'jane@example.com');
    await page.fill('input[name="company"]', 'Acme Corp');
    await page.fill('textarea[name="message"]', 'Interested in your product');
    await page.check('input[name="consent"]');

    // Submit form
    await page.click('button[type="submit"]');

    // Verify success message
    await expect(page.locator('.success-message')).toBeVisible();
    await expect(page.locator('.success-message')).toContainText(
      'Thank you for your message'
    );

    // Verify form is reset
    await expect(page.locator('input[name="name"]')).toHaveValue('');
  });

  test('shows validation errors for invalid input', async ({ page }) => {
    await page.goto('/contact');

    // Submit without filling form
    await page.click('button[type="submit"]');

    // Verify error messages appear
    await expect(page.locator('.error-message')).toHaveCount(3);
    await expect(page.locator('.error-message').first()).toContainText(
      'Name is required'
    );
  });
});
